import{_ as a,o as i,c as o,ag as r}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"es/home/overview.md","filePath":"es/home/overview.md"}'),s={name:"es/home/overview.md"};function n(l,e,t,c,d,u){return i(),o("div",null,[...e[0]||(e[0]=[r('<p>Una guía práctica para entender, diseñar y seleccionar sistemas industriales — sin complejidad innecesaria.</p><hr><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Industrial Systems Handbook es una colección curada de conceptos, componentes y conocimiento práctico utilizados en entornos industriales.</p><p>Está diseñado para ayudarte a entender cómo funcionan realmente los sistemas y tomar mejores decisiones de ingeniería en escenarios reales.</p><p>Este handbook no reemplaza hojas de datos (<em>datasheets</em>), normas o diseño detallado.<br> Te ayuda a interpretarlos y utilizarlos de forma efectiva.</p><hr><h2 id="por-que-existe" tabindex="-1">Por qué existe <a class="header-anchor" href="#por-que-existe" aria-label="Permalink to &quot;Por qué existe&quot;">​</a></h2><p>En la ingeniería del mundo real, los problemas rara vez comienzan desde la teoría.</p><p>Comienzan con preguntas como:</p><ul><li>¿Qué cable se debe usar en esta instalación?</li><li>¿Cuál es la diferencia entre dos componentes similares?</li><li>¿Por qué un sistema no se comporta como se espera?</li></ul><p>La mayoría de los recursos disponibles son demasiado básicos o demasiado complejos para aplicarse rápidamente.</p><p>Este handbook cierra esa brecha enfocándose en la comprensión práctica.</p><hr><h2 id="para-quien-es" tabindex="-1">Para quién es <a class="header-anchor" href="#para-quien-es" aria-label="Permalink to &quot;Para quién es&quot;">​</a></h2><ul><li>Estudiantes que aprenden sistemas industriales</li><li>Ingenieros que ingresan o hacen transición a la industria</li><li>Técnicos que trabajan con equipos reales</li><li>Cualquier persona que necesite entender cómo se comportan los sistemas en la práctica</li></ul><hr><h2 id="que-encontraras" tabindex="-1">Qué encontrarás <a class="header-anchor" href="#que-encontraras" aria-label="Permalink to &quot;Qué encontrarás&quot;">​</a></h2><ul><li>Fundamentos eléctricos</li><li>Sistemas de potencia y protección</li><li>Cables y prácticas de instalación</li><li>Equipos industriales (motores, variadores, sensores, actuadores)</li><li>Sistemas de control (PLC, HMI, SCADA)</li><li>Instrumentación y señales</li><li>Redes industriales</li><li>Consideraciones prácticas de ingeniería</li></ul><hr><h2 id="que-no-encontraras" tabindex="-1">Qué no encontrarás <a class="header-anchor" href="#que-no-encontraras" aria-label="Permalink to &quot;Qué no encontrarás&quot;">​</a></h2><ul><li>Sesgo hacia marcas específicas</li><li>Explicaciones excesivamente académicas</li><li>Complejidad innecesaria</li></ul><p>Cuando se requiera mayor detalle, consulta:</p><ul><li>Hojas de datos (<em>datasheets</em>)</li><li>Normas</li><li>Documentación de fabricantes</li></ul><hr><h2 id="filosofia" tabindex="-1">Filosofía <a class="header-anchor" href="#filosofia" aria-label="Permalink to &quot;Filosofía&quot;">​</a></h2><p>Este handbook se enfoca en la comprensión práctica.</p><p>El objetivo es ayudarte a:</p><ul><li>Tomar mejores decisiones</li><li>Hacer mejores preguntas técnicas</li><li>Aprender más rápido a partir de sistemas reales y documentación</li></ul><hr><h2 id="naturaleza-del-proyecto" tabindex="-1">Naturaleza del proyecto <a class="header-anchor" href="#naturaleza-del-proyecto" aria-label="Permalink to &quot;Naturaleza del proyecto&quot;">​</a></h2><p>Este es un handbook en evolución continua.</p><p>El contenido se publica como una estructura completa y se refina con el tiempo para mejorar claridad, profundidad y usabilidad.</p><hr><h2 id="apoyo-y-contribucion" tabindex="-1">Apoyo y contribución <a class="header-anchor" href="#apoyo-y-contribucion" aria-label="Permalink to &quot;Apoyo y contribución&quot;">​</a></h2><p>Si encuentras útil este proyecto:</p><ul><li>Puedes apoyarlo</li><li>Puedes contribuir al contenido</li></ul>',37)])])}const h=a(s,[["render",n]]);export{m as __pageData,h as default};
